mapper.sql:
SELECT A.RATE_CD , A.RATE_NM , B.PRDT_ID , B.PRDT_CODE , B.PRDT_NM , C.OLD_YN , DECODE(C.OLD_YN, 'N', '신품', '중고') AS OLD_NM , C.APPL_STRT_DT , C.APPL_END_DT , C.SUBSD_AMT FROM MSP_RATE_MST A , CMN_INTM_MDL B , ( SELECT /*+ INDEX(A MSP_OFCL_SUBSD_MST_IDX2 )*/ A.RATE_CD, A.PRDT_ID, A.OLD_YN, A.SUBSD_AMT, A.APPL_STRT_DT, A.APPL_END_DT FROM MSP_OFCL_SUBSD_MST A WHERE #{stdrDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT
AND A.RATE_CD = #{rateCd}
AND A.PRDT_ID = #{prdtId}
GROUP BY A.RATE_CD, A.PRDT_ID, A.OLD_YN, A.SUBSD_AMT, A.APPL_STRT_DT, A.APPL_END_DT ) C WHERE A.RATE_CD = C.RATE_CD AND B.PRDT_ID = C.PRDT_ID ORDER BY A.RATE_NM, B.PRDT_NM

mapper.select:
/* subsdMapper.getPrdtIndCd */
SELECT	PRDT_IND_CD
FROM	CMN_INTM_MDL
WHERE PRDT_ID	= #{prdtId}

mapper.sql:
/* subsdMapper.getSubsdAmtDtlInfo */ SELECT A.RATE_CD , FN_GET_CODENM('CMN0046', B.RATE_GRP_CD) AS RATE_GRP_NM , B.RATE_NM , A.PRDT_ID , C.PRDT_CODE , C.PRDT_NM , A.OLD_YN , DECODE(A.OLD_YN, 'N', '신품', '중고') AS OLD_NM , A.OPER_TYPE , FN_GET_CODENM('CMN0049', A.OPER_TYPE) AS OPER_TYPE_NM , A.AGRM_TRM , FN_GET_CODENM('CMS0029', A.AGRM_TRM) AS AGRM_TRM_NM , A.APPL_STRT_DT , A.APPL_END_DT , A.SUBSD_AMT , FN_GET_USRNM( A.REGST_ID ) AS REGST_NM , TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM , FN_GET_USRNM( A.RVISN_ID ) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MSP_OFCL_SUBSD_MST A , MSP_RATE_MST B , CMN_INTM_MDL C WHERE #{stdrDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT
AND A.RATE_CD = #{rateCd}
AND A.PRDT_ID = #{prdtId}
AND A.OLD_YN = #{oldYn}
AND A.OPER_TYPE = #{operType}
AND A.AGRM_TRM = #{agrmTrm}
AND A.RATE_CD = B.RATE_CD AND B.APPL_END_DT = '99991231' AND A.PRDT_ID = C.PRDT_ID

mapper.select:
/* subsdMapper.getPrdtComboList */ SELECT A.PRDT_ID AS VALUE , A.PRDT_NM || '[' || A.PRDT_CODE || ']' AS TEXT FROM CMN_INTM_MDL A WHERE A.RPRS_YN = 'Y'
AND A.PRDT_TYPE_CD = '01'
AND A.PRDT_DT = '99991231' ORDER BY 2

/* subsdMapper.getCommonGridList */
SELECT	'' CHK_YN
		, CD_VAL
		, CD_DSC AS CD_NM
FROM	CMN_GRP_CD_MST
WHERE	GRP_ID	= #{grpId}
AND		USG_YN	= 'Y'

AND     CD_VAL  <>  #{optVal}

ORDER BY ETC1

/* subsdMapper.getSubsdEndDt */
SELECT  DISTINCT RATE_CD
        , PRDT_ID
        , OLD_YN
        , OPER_TYPE
        , AGRM_TRM
        , APPL_END_DT
        , TO_CHAR(TO_DATE(#{applStrtDt}, 'YYYYMMDD') - 1, 'YYYYMMDD') AS NEW_APPL_END_DT
        , #{userId} AS USER_ID
FROM    MSP_OFCL_SUBSD_MST
WHERE   RATE_CD     = #{rateCd}
AND     PRDT_ID     = #{prdtId}
AND     OLD_YN      = #{oldYn}
AND     OPER_TYPE   = #{operType}
AND     AGRM_TRM    = #{agrmTrm}
AND     APPL_END_DT  >=  #{applStrtDt}
AND     ROWNUM      = 1

mapper.update:
/* subsdMapper.updateOfclSubsdEndDt */
UPDATE	MSP_OFCL_SUBSD_MST
SET		APPL_END_DT 	= #{newApplEndDt, jdbcType=VARCHAR}
		, RVISN_ID		= #{userId, jdbcType=VARCHAR}
		, RVISN_DTTM	= SYSDATE
WHERE	RATE_CD			= #{rateCd, jdbcType=VARCHAR}
AND		PRDT_ID			= #{prdtId, jdbcType=VARCHAR}
AND		OLD_YN			= #{oldYn, jdbcType=VARCHAR}
AND		OPER_TYPE		= #{operType, jdbcType=VARCHAR}
AND		AGRM_TRM		= #{agrmTrm, jdbcType=VARCHAR}
AND		APPL_END_DT		= #{applEndDt, jdbcType=VARCHAR}

mapper.insert:
/* subsdMapper.insertOfclSubsdMst */
INSERT INTO MSP_OFCL_SUBSD_MST (
	RATE_CD
	, PRDT_ID
	, OLD_YN
	, AGRM_TRM
	, OPER_TYPE
	, APPL_END_DT
	, APPL_STRT_DT
	, SUBSD_AMT
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{rateCd, jdbcType=VARCHAR}
	, #{prdtId, jdbcType=VARCHAR}
	, NVL(#{oldYn, jdbcType=VARCHAR}, 'N')
	, #{agrmTrm, jdbcType=VARCHAR}
	, #{operType, jdbcType=VARCHAR}
	, '99991231'
	, #{applStrtDt, jdbcType=VARCHAR}
	, #{subsdAmt, jdbcType=INTEGER}
	, #{userId, jdbcType=VARCHAR}
	, SYSDATE
	, #{userId, jdbcType=VARCHAR}
	, SYSDATE
)

mapper.update:
/* subsdMapper.updateSubsdAmtInfo */
UPDATE  MSP_OFCL_SUBSD_MST
SET     SUBSD_AMT       = #{subsdAmt, jdbcType=INTEGER}
        , RVISN_ID      = #{sessionUserId, jdbcType=VARCHAR}
        , RVISN_DTTM    = SYSDATE 
WHERE   RATE_CD         = #{rateCd, jdbcType=VARCHAR}
AND     PRDT_ID         = #{prdtId, jdbcType=VARCHAR}
AND     OLD_YN          = #{oldYn, jdbcType=VARCHAR}
AND     APPL_END_DT     = #{applEndDt, jdbcType=VARCHAR}
AND     APPL_STRT_DT    = #{applStrtDt, jdbcType=VARCHAR}

AND     OPER_TYPE       = #{operType, jdbcType=VARCHAR}


AND     AGRM_TRM        = #{agrmTrm, jdbcType=VARCHAR}

mapper.select:
/* subsdMapper.getCmnGrpCdListByEtc5 */
SELECT	CD_VAL
	  , CD_DSC
FROM	CMN_GRP_CD_MST
WHERE	GRP_ID	= #{grpId}
AND		USG_YN	= 'Y'

AND     ETC5 = #{optVal}

